const update = $input.first().json;
const query = update.callback_query;
const data = query.data || '';

// Format: "sign_{sourceEntryId}_{action}"
// sourceEntryId = Dochádzka/Pokladňa entry ID (N8N request-sign flow uses payload.sourceId)
// NOTE: The request-sign N8N flow must use sourceId (not podpisId) in callback_data!
if (!data.startsWith('sign_')) {
  return [{ json: { skip: true, data } }];
}

const lastIdx = data.lastIndexOf('_');
const action = data.substring(lastIdx + 1);      // 'confirm' or 'reject'
const sourceId = data.substring(5, lastIdx);     // Dochádzka/Pokladňa entry ID

if ((action !== 'confirm' && action !== 'reject') || !sourceId) {
  return [{ json: { skip: true, data } }];
}

const confirmed = action === 'confirm';
const callbackQueryId = query.id;
const chatId = String(query.message.chat.id);
const messageId = query.message.message_id;
const originalText = query.message.text || '';
const fromFirst = query.from.first_name || '';
const fromLast = query.from.last_name || '';
const fromName = (fromFirst + ' ' + fromLast).trim();
const fromChatId = String(query.from.id);  // Telegram user ID who clicked
const confirmText = confirmed
  ? String.fromCharCode(10004) + ' Potvrdené'
  : String.fromCharCode(10060) + ' Odmietnuté';

return [{ json: {
  action, sourceId, confirmed, callbackQueryId, chatId, messageId,
  originalText, fromName, fromChatId, confirmText, skip: false
} }];

// Find the podpis entry matching sourceId (Dochádzka/Pokladňa entry ID)
// and fromChatId (Telegram user who clicked confirm/reject)
const response = $input.first().json;
const sourceId   = $('Parse Callback').first().json.sourceId;
const fromChatId = $('Parse Callback').first().json.fromChatId;
const confirmed  = $('Parse Callback').first().json.confirmed;

// Memento API may return array or { entries: [...] }
const entries = Array.isArray(response)
  ? response
  : (Array.isArray(response.entries) ? response.entries
     : (Array.isArray(response.data) ? response.data : []));

const match = entries.find(function(e) {
  const fields = e.fields || [];
  var zdrojVal = '';
  var chatVal  = '';
  for (var i = 0; i < fields.length; i++) {
    if (fields[i].name === 'Zdroj ID') zdrojVal = String(fields[i].value || '');
    if (fields[i].name === 'TG Chat ID') chatVal = String(parseFloat(fields[i].value || 0));
  }
  return zdrojVal === String(sourceId) && chatVal === String(parseFloat(fromChatId || 0));
});

if (!match) {
  return [{ json: {
    found: false,
    sourceId: sourceId,
    fromChatId: fromChatId,
    entriesScanned: entries.length
  }}];
}

// Read Knižnica to determine source library
var kniznica = '';
(match.fields || []).forEach(function(f) {
  if (f.name === 'Kni\u017enica') kniznica = String(f.value || '');
});

// Map library name → Cloud API library ID + status field name
var libMap = {};
libMap['Doch\u00e1dzka'] = { libId: 'zNoMvrv8U', statusField: 'Stav podpisov' };
libMap['Pokladňa']      = { libId: 'g9eS5Ny2E', statusField: 'Stav podpisu'  };
var lib = libMap[kniznica] || null;

return [{ json: {
  found: true,
  podpisCloudId:   match.id,
  stavValue:       confirmed ? 'Potvrdil' : 'Odmietol',
  sourceId:        sourceId,
  sourceLibId:     lib ? lib.libId : '',
  sourceField:     lib ? lib.statusField : '',
  hasSource:       !!(lib && sourceId),
  kniznica:        kniznica
}}];
